module RefModule(clk, reset, q);

    input clk;
    input reset;
    output [3:0] q;
    reg [3:0] q;
    initial q = 4'b0001;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
        begin
            if (reset)
                q <= 4'b0001;
            else
                q <= {q[2:0], q[3]};
        end

endmodule
